package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Ave; public class Aguia extends Ave implements Voo, Predacao { public Aguia(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " emite um grito agudo."); } public void comer() { System.out.println(getNome() + " está comendo carne de pequenos animais."); } public void voar() { System.out.println(getNome() + " está voando em grandes altitudes."); } public void cacar() { System.out.println(getNome() + " está caçando uma presa do alto."); } }
